async function getPosts(req, res) {
  const posts = await db.query('SELECT * FROM posts');
  for (const post of posts.rows) {
    const author = await db.query('SELECT * FROM users WHERE id = $1', [post.user_id]);
    post.author = author.rows[0];
  }
  res.json(posts.rows);
}

