const db = require('../db');

async function searchProducts(req, res) {
  const { query, category, minPrice, maxPrice } = req.query;
  const all = await db.query('SELECT * FROM products');
  const filtered = all.rows
    .filter(p => p.name.includes(query))
    .filter(p => !category || p.category === category)
    .filter(p => p.price >= (minPrice || 0) && p.price <= (maxPrice || Infinity))
    .sort((a, b) => a.price - b.price);
  res.json(filtered);
}

module.exports = { searchProducts };

starter_code.controllers/register.js:
const bcrypt = require('bcrypt');
const db = require('../db');
const mailer = require('../mailer');
const logger = require('../logger');

async function register(req, res) {
  const { email, password, name } = req.body;
  if (!email || !password || !name) return res.status(400).json({ error: 'Missing fields' });
  if (password.length < 8) return res.status(400).json({ error: 'Password too short' });
  const existing = await db.query('SELECT id FROM users WHERE email = $1', [email]);
  if (existing.rows.length) return res.status(409).json({ error: 'Email taken' });
  const hash = await bcrypt.hash(password, 12);
  const user = await db.query('INSERT INTO users (email, password, name) VALUES ($1,$2,$3) RETURNING id', [email, hash, name]);
  await mailer.send({ to: email, subject: 'Welcome!', body: `Hi ${name}` });
  logger.info(`New user registered: ${email}`);
  res.status(201).json({ userId: user.rows[0].id });
}

module.exports = { register };

